def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_factor = np.tanh((cap - item) / (item + 1)) * 10
        complexity = 1.0
        decay = 1.0
        amplification = 1.0
        interference = 0.0
        for x in range(1, 15):
            decay *= 0.97 + 0.005 * ((x * item) % 3)
            if (item * x) % 4 == 0:
                amplification *= 1.03 + 0.004 * x
            else:
                amplification *= 0.99 - 0.003 * (x % 5)
            complexity += np.sin(item * x) * np.log1p(cap / (x + 1))
            interference += ((cap % (x + 2)) - (item * x) % 6) * 0.01
            if cap % (x + 3) == 0 and x % 2 == 1:
                interference += np.exp(-abs(item - cap/(x+1))) * 0.5
            if x == 7:
                for y in range(1, 7):
                    diff = cap - item * y * y
                    if diff > 0:
                        if diff % (y+3) == 0:
                            interference -= np.log1p(diff) / (y+2)
                        else:
                            interference += np.sqrt(abs(diff)) / (y+4)
                    else:
                        interference -= abs(diff)**1.1 / (y+5)
            if (x * item) % 5 == 0:
                complexity *= 1.02
            else:
                complexity *= 0.98
        score = (base_factor + complexity) * decay + interference
        if score < 0:
            priorities[i] = -score * (np.sqrt(cap + item) + np.log1p(cap))
        else:
            if cap < item * 2:
                priorities[i] = -score / (cap + 1) * np.exp(-item / (cap + 0.1))
            elif cap < item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + item/cap)
            else:
                priorities[i] = -score / (cap ** 0.7 + 1) * (1 + np.log1p(item))
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        if item / cap > 1.2:
            priorities[i] *= 1.2
        if (cap + int(item)) % 2 == 1:
            priorities[i] *= 1.03
        if (int(cap * item) + i) % 10 == 0:
            priorities[i] *= 0.90
        return priorities
